/// <summary>
/// The <c>ETG_InventFairValueController</c> class is the controller class for working with
/// service operations.
/// </summary> 
class ETG_InventFairValueController extends SysOperationServiceController
{
}

Method.Source:
/// <summary>
/// To construct LocationRecordsController class
/// </summary>
public static ETG_InventFairValueController construct(SysOperationExecutionMode _executionMode = SysOperationExecutionMode::Synchronous)
{
    ETG_InventFairValueController controller;
    controller = new ETG_InventFairValueController();
    controller.parmExecutionMode(_executionMode);
    return controller;
}

/// <summary>
/// Main method of LocationRecordsController class
/// </summary>
public static void main(Args _args)
{
    ETG_InventFairValueController   controller;
    ETG_InventFairValueContract     contract;

    controller  = ETG_InventFairValueController::construct();
    controller.parmArgs(_args);
    contract    =  controller.getDataContractObject();
    contract.parmInventFairValueHeaderTable(_args.caller().parmInventFairValueHeaderTable());
    controller.startOperation();
    _args.caller().refreshDS();

}

/// <summary>
/// To set caption of a batch job
/// </summary>
public ClassDescription defaultCaption()
{
    return "@ETG_New:ETGLocationRecordsCaption";
}

/// <summary>
/// Starts the operation
/// </summary>
/// <returns>Returns the status of start operation command</returns>
public SysOperationStartResult startOperation()
{
    SysOperationStartResult ret;
    ret = super();
    return ret;
}

/// <summary>
/// Validates the dialog parameters
/// </summary>
/// <returns>Retuend true/false</returns>
protected boolean validate()
{
    ETG_InventFairValueContract contract;

    boolean isValid = true;
    contract =  this.getDataContractObject();

    if(!contract.parmPerDate())
    {
        isValid = checkFailed("@ETG_New:ETGPerDateValidation");
    }
    if(!contract.parmvertical())
    {
        isValid = checkFailed("@ETG_New:ETGVerticalValidation");
    }
    if(!contract.parmSubvertical())
    {
        isValid = checkFailed("@ETG_New:ETGSubVerticalValidation");
    }
    if(!contract.parmCommodity())
    {
        isValid = checkFailed("@ETG_New:ETGCommodityValidation");
    }
    if(!contract.parmSubCommodity())
    {
        isValid = checkFailed("@ETG_New:ETGSubCommodityValidation");
    }
    return isValid;
}
